                        <p className="text-slate-500 text-sm mb-6 max-w-[250px] mx-auto">Server backend tidak merespon atau sesi terdahulu sangkut.</p>
                        <button onClick={connectWA} className="px-8 py-3 bg-slate-900 text-white rounded-xl font-black text-xs uppercase hover:bg-slate-800 transition">Cuba Semula</button>
                      </div>
                    ) : qrStatus === 'qr_ready' ? (
                      <div className="text-center space-y-6">
                        <QRCodeImage value={qr} />
                        <p className="text-sm font-bold text-slate-500">Imbas QR menggunakan WhatsApp anda</p>
                        <Loader2 className="animate-spin text-green-500 mx-auto mt-4" />
                        <p className="text-[10px] font-black text-slate-400 uppercase">Menunggu Imbasan... (Auto Refresh)</p>
                      </div>
                    ) : qrStatus === 'connected' ? (
                      <div className="text-center">
                        <div className="w-24 h-24 bg-green-100 text-green-600 rounded-[2rem] flex items-center justify-center mx-auto mb-6 shadow-xl shadow-green-50">
                          <CheckCircle2 size={48} />
                        </div>
                        <h4 className="text-2xl font-black mb-2">Terhubung Secara Automatik!</h4>
                        <p className="text-slate-400 font-bold text-sm mb-8">WhatsApp anda sedia untuk menghantar blast.</p>
                        <button onClick={logoutWA} className="px-8 py-3 bg-red-50 text-red-500 rounded-xl font-black text-xs uppercase hover:bg-red-100 transition">Putuskan Sambungan</button>
                      </div>
                    ) : (
                      <div className="text-center">
                        <div className="w-20 h-20 bg-slate-200 rounded-3xl flex items-center justify-center mx-auto mb-6 text-slate-400">
                          <QrCode size={40} />
                        </div>
                        <button onClick={connectWA} className="px-10 py-5 bg-slate-900 text-white rounded-2xl font-black hover:bg-green-500 transition-all shadow-xl shadow-slate-200 uppercase tracking-widest flex items-center gap-2">
                          <Zap size={20} className="fill-current" />
                          Jana QR Code
                        </button>
                      </div>
                    )}
                  </div>
                </div>

                <div className="space-y-6">
                  <div className="bg-green-500 rounded-[3rem] p-10 text-white shadow-xl shadow-green-100 relative overflow-hidden group">
                    <h3 className="text-3xl font-black mb-4">Fast Blast</h3>
                    <p className="font-bold opacity-80 mb-10 max-w-[280px]">Hantar ribuan mesej serta-merta tanpa perlu simpan nombor.</p>
                    <button onClick={() => setActiveTab('blast')} className="px-10 py-4 bg-white text-green-600 rounded-2xl font-black uppercase text-sm shadow-lg hover:scale-105 transition-all flex items-center gap-2 relative z-10">
                      Mula Sekarang <ArrowRight size={18} />
                    </button>
                    <Send className="absolute -right-8 -bottom-8 opacity-10 group-hover:scale-110 transition duration-700" size={220} />
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* Blast Tab */}
          {activeTab === 'blast' && (
            <div className="max-w-6xl mx-auto animate-in fade-in duration-500">
              <div className="flex justify-between items-end mb-10">
                <div>
                  <h2 className="text-4xl font-black text-slate-900 tracking-tight">New Blast Campaign</h2>
                  <p className="text-slate-500 font-medium">Kos: <span className="text-green-600 font-bold">1 Unit</span> / mesej</p>
                </div>
                <div className={`flex items-center gap-2 px-5 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest border-2 ${isDeviceLinked ? 'bg-green-50 text-green-600 border-green-100' : 'bg-red-50 text-red-500 border-red-100'}`}>
                  <div className={`w-2 h-2 rounded-full ${isDeviceLinked ? 'bg-green-500' : 'bg-red-500 animate-pulse'}`}></div>
                  {isDeviceLinked ? 'Device Linked' : 'No Device Linked'}
                </div>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
                <div className="lg:col-span-7 space-y-6">
                  <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm space-y-8">
                    <div className="space-y-3">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sumber Sasaran (Target)</label>
                      <select value={targetSource} onChange={(e) => setTargetSource(e.target.value)} className="w-full p-5 bg-slate-50 border-2 border-slate-50 rounded-2xl font-bold text-slate-700 outline-none focus:border-green-500 transition-all">
                        <option value="manual">Kemasukan Manual (Guna Kod Negara, Cth: 6012...)</option>
                        <option value="csv" disabled>Import dari CSV (Akan Datang)</option>
                      </select>
                    </div>

                    {targetSource === 'manual' && (
                      <div className="space-y-3">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Senarai Nombor</label>
                        <textarea value={manualNumbers} onChange={(e) => setManualNumbers(e.target.value)} className="w-full p-5 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none font-medium text-slate-700 focus:border-green-500 transition-all resize-none" placeholder="6012345678, 6019876543..." />
                      </div>
                    )}

                    <div className="space-y-3">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Kandungan Mesej</label>
                      <textarea value={message} onChange={(e) => setMessage(e.target.value)} className="w-full p-5 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none h-40 font-medium text-slate-700 focus:border-green-500 transition-all resize-none" placeholder="Taipkan mesej WhatsApp anda di sini..." />
                    </div>
                  </div>

                  {isBlasting ? (
                    <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
                      <div className="flex justify-between items-center mb-4">
