                  ) : (
                    <button onClick={startBlast} className="w-full py-6 bg-green-500 text-white rounded-[2.5rem] font-black text-xl hover:bg-green-600 shadow-xl shadow-green-200 transition-all flex items-center justify-center gap-3">
                      <Send size={24} /> MULA KEMPEN BLAST
