                <div className="lg:col-span-5">
                  <div className="bg-[#e5ddd5] rounded-[3rem] p-4 shadow-2xl border-[12px] border-slate-900 h-[650px] relative flex flex-col overflow-hidden">
                    <div className="bg-[#075e54] text-white p-4 rounded-t-[2rem] -mx-4 -mt-4 flex items-center gap-3 z-10 shadow-md">
                      <div className="w-9 h-9 rounded-full bg-slate-200 flex items-center justify-center overflow-hidden">
                        <User size={20} className="text-slate-400 mt-2" />
                      </div>
                      <div>
                        <p className="text-xs font-bold">Customer Preview</p>
                        <p className="text-[9px] opacity-70">online</p>
                      </div>
                    </div>
                    <div className="flex-1 overflow-y-auto p-4 space-y-4 pt-6">
                      <div className="bg-white p-3 rounded-2xl rounded-tl-none shadow-sm max-w-[85%] relative">
